225	// OperatorPromptSubmit implements the operatorPromptSubmit mutation: it
226	// validates the CSRF token from the request header, deduplicates within a
227	// 24h window by idempotency key, and (on first submission) creates a new
228	// operator-prompt bead in the proposed status with an audit event capturing
229	// the originating identity (localhost user OR ts-net WhoIs).
230	func (r *mutationResolver) OperatorPromptSubmit(ctx context.Context, input OperatorPromptSubmitInput) (*OperatorPromptSubmitResult, error) {
231		if r.WorkingDir == "" {
232			return nil, fmt.Errorf("working directory not configured")
233		}
234		if strings.TrimSpace(input.Prompt) == "" {
235			return nil, fmt.Errorf("operator-prompts: prompt is required")
236		}
237		if strings.TrimSpace(input.IdempotencyKey) == "" {
238			return nil, fmt.Errorf("operator-prompts: idempotency key is required")
239		}
240	
241		httpReq := httpRequestFromContext(ctx)
242		if httpReq == nil {
243			// No request context means we cannot enforce CSRF, which is the
244			// whole point of the gate. Refuse rather than fail open.
245			return nil, errCSRF
246		}
247		if err := validateSameOrigin(httpReq); err != nil {
248			return nil, err
249		}
250		presented := httpReq.Header.Get(CSRFHeaderName)
251		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
252			return nil, errCSRF
253		}
254	
255		cap := r.PromptCapBytes
256		if cap <= 0 {
257			cap = DefaultOperatorPromptCapBytes
258		}
259		if observed := len(input.Prompt); observed > cap {
260			return nil, promptCapError(observed, cap)
261		}
262	
263		cache := r.OperatorPromptIdempotency
264		if cache == nil {
265			return nil, fmt.Errorf("operator-prompts: idempotency cache not configured")
266		}
267	
268		store := r.beadStore()
269		if id, ok := cache.Lookup(input.IdempotencyKey); ok {
270			existing, err := store.Get(id)
271			if err == nil {
272				return &OperatorPromptSubmitResult{
273					Bead:         beadModelFromBead(existing),
274					Deduplicated: true,
275				}, nil
276			}
277			// Cached ID points to a missing bead — fall through and create a
278			// fresh bead, overwriting the stale entry below.
279		}
280	
281		tier := bead.DefaultPriority
282		if input.Tier != nil {
283			tier = *input.Tier
284		}
285		b := bead.NewOperatorPromptBead(input.Prompt, tier)
286		if err := store.Create(b); err != nil {
287			return nil, err
288		}
289	
290		identity := operatorPromptIdentity(httpReq)
291		originNodeID := httpReq.Header.Get("X-Tailscale-Node")
292		if originNodeID == "" {
293			// Loopback callers do not carry an X-Tailscale-Node header; the
294			// origin and the receiving node are the same machine, so record the
295			// receiving node ID for symmetry.
296			originNodeID = r.NodeID
297		}
298		buildSHA := r.BuildSHA
299		if buildSHA == "" {
300			buildSHA = "unknown"
301		}
302		approvalMode := "manual"
303		if input.AutoApprove != nil && *input.AutoApprove {
304			approvalMode = "auto-requested"
305		}
306		requestID := httpReq.Header.Get("X-Request-Id")
307		if requestID == "" {
308			requestID = newRequestID()
309		}
310		promptHash := sha256.Sum256([]byte(input.Prompt))
311		promptSHA := hex.EncodeToString(promptHash[:])
312		auditBody := fmt.Sprintf(
313			"identity=%s remote_addr=%s tailscale_user=%s tailscale_node=%s "+
314				"origin_node_id=%s receiving_node_id=%s build_sha=%s "+
315				"approval_mode=%s request_id=%s prompt_sha256=%s "+
316				"idempotency_key=%s",
317			identity.kind,
318			httpReq.RemoteAddr,
319			httpReq.Header.Get("X-Tailscale-User"),
320			httpReq.Header.Get("X-Tailscale-Node"),
321			originNodeID,
322			r.NodeID,
323			buildSHA,
324			approvalMode,
325			requestID,
326			promptSHA,
327			input.IdempotencyKey,
328		)
329		if err := store.AppendEvent(b.ID, bead.BeadEvent{
330			Kind:    OperatorPromptEventKind,
331			Summary: "operator prompt submitted",
332			Body:    auditBody,
333			Actor:   identity.actor,
334			Source:  "graphql:operatorPromptSubmit",
335		}); err != nil {
336			return nil, fmt.Errorf("operator-prompts: append audit event: %w", err)
337		}
338	
339		cache.Store(input.IdempotencyKey, b.ID)
340	
341		// Auto-approve path: only when the caller asked for it AND the identity
342		// is on the per-project allowlist. ts-net identities never qualify
343		// (locked Story 15 decision). On denial we leave the bead in proposed
344		// and return autoApproved=false; the caller can still issue a manual
345		// operatorPromptApprove later from a permitted identity.
346		autoApproved := false
347		if input.AutoApprove != nil && *input.AutoApprove {
348			if r.canAutoApprove(identity) {
349				if err := store.Update(b.ID, func(updated *bead.Bead) {
350					updated.Status = bead.StatusOpen
351				}); err != nil {
352					return nil, fmt.Errorf("operator-prompts: auto-approve update: %w", err)
353				}
354				if err := store.AppendEvent(b.ID, bead.BeadEvent{
355					Kind:    OperatorPromptApproveEventKind,
356					Summary: "operator prompt auto-approved on submit",
357					Body:    fmt.Sprintf("identity=%s actor=%s", identity.kind, identity.actor),
358					Actor:   identity.actor,
359					Source:  "graphql:operatorPromptSubmit",
360				}); err != nil {
361					return nil, fmt.Errorf("operator-prompts: append auto-approve event: %w", err)
362				}
363				autoApproved = true
364			}
365		}
366	
367		// Re-read so the audit event materializes in the returned snapshot.
368		persisted, err := store.Get(b.ID)
369		if err != nil {
370			return nil, err
371		}
372		return &OperatorPromptSubmitResult{
373			Bead:         beadModelFromBead(persisted),
374			Deduplicated: false,
375			AutoApproved: autoApproved,
376		}, nil
377	}
