425	// OperatorPromptCancel implements the operatorPromptCancel mutation:
426	// validates CSRF, verifies the bead is a proposed operator-prompt,
427	// transitions proposed → cancelled, and appends an audit event recording
428	// the canceller. Cancellation is open to any trusted identity (the
429	// allowlist gates auto-approval, not rejection) so an operator who
430	// regrets a submission can withdraw it without first being added to the
431	// approval allowlist.
432	func (r *mutationResolver) OperatorPromptCancel(ctx context.Context, id string) (*OperatorPromptCancelResult, error) {
433		httpReq, ident, err := r.requireOperatorPromptCSRF(ctx)
434		if err != nil {
435			return nil, err
436		}
437	
438		store := r.beadStore()
439		existing, err := store.Get(id)
440		if err != nil {
441			return nil, err
442		}
443		if existing.IssueType != bead.IssueTypeOperatorPrompt {
444			return nil, fmt.Errorf("operator-prompts: bead %s is not an operator-prompt (issue_type=%q)", id, existing.IssueType)
445		}
446		if existing.Status != bead.StatusProposed {
447			return nil, fmt.Errorf("operator-prompts: bead %s is not in proposed status (got %q); cannot cancel", id, existing.Status)
448		}
449		if err := store.Update(id, func(b *bead.Bead) {
450			b.Status = bead.StatusCancelled
451		}); err != nil {
452			return nil, err
453		}
454		if err := store.AppendEvent(id, bead.BeadEvent{
455			Kind:    OperatorPromptCancelEventKind,
456			Summary: "operator prompt cancelled",
457			Body:    fmt.Sprintf("identity=%s actor=%s remote_addr=%s", ident.kind, ident.actor, httpReq.RemoteAddr),
458			Actor:   ident.actor,
459			Source:  "graphql:operatorPromptCancel",
460		}); err != nil {
461			return nil, fmt.Errorf("operator-prompts: append cancel audit event: %w", err)
462		}
463		persisted, err := store.Get(id)
464		if err != nil {
465			return nil, err
466		}
467		return &OperatorPromptCancelResult{Bead: beadModelFromBead(persisted)}, nil
468	}
469	
470	// requireOperatorPromptCSRF is the shared preamble for the approve and
471	// cancel mutations. It pulls the originating *http.Request from context
472	// (the server's GraphQL handler installs it via WithHTTPRequest), enforces
473	// the CSRF token check against the configured store, and returns the
474	// classified identity.
475	func (r *mutationResolver) requireOperatorPromptCSRF(ctx context.Context) (*http.Request, operatorPromptIdentityInfo, error) {
476		if r.WorkingDir == "" {
477			return nil, operatorPromptIdentityInfo{}, fmt.Errorf("working directory not configured")
478		}
479		httpReq := httpRequestFromContext(ctx)
480		if httpReq == nil {
481			return nil, operatorPromptIdentityInfo{}, errCSRF
482		}
483		presented := httpReq.Header.Get(CSRFHeaderName)
484		if r.CSRFTokens == nil || !r.CSRFTokens.Validate(presented) {
485			return nil, operatorPromptIdentityInfo{}, errCSRF
486		}
487		return httpReq, operatorPromptIdentity(httpReq), nil
488	}
489	
490	// canAutoApprove reports whether ident is authorized to approve operator
491	// prompts under the resolver's allowlist. ts-net identities are denied
492	// unconditionally (locked Story 15 decision). For localhost identities,
493	// the literal sentinel "localhost" matches any actor; otherwise the
494	// allowlist entry must equal the identity's actor string.
495	func (r *Resolver) canAutoApprove(ident operatorPromptIdentityInfo) bool {
496		if ident.kind != "localhost" {
497			return false
498		}
499		if len(r.OperatorPromptAutoApproveAllowlist) == 0 {
500			return false
501		}
502		for _, entry := range r.OperatorPromptAutoApproveAllowlist {
503			if entry == OperatorPromptAllowlistLocalhostSentinel {
504				return true
505			}
506			if entry == ident.actor {
507				return true
508			}
509		}
510		return false
511	}
512	
513	type operatorPromptIdentityInfo struct {
514		kind  string // "tsnet" or "localhost"
515		actor string
516	}
517	
518	// operatorPromptIdentity classifies the originating identity for audit
519	// logging. ts-net peers are identified by the X-Tailscale-User header
520	// injected by tsnetMiddleware; loopback callers fall back to a
521	// "localhost:<remote-addr>" actor string. A bare "anonymous" actor is used
522	// only when neither signal is present (which should not occur because
523	// requireTrusted gates the GraphQL endpoint).
524	func operatorPromptIdentity(r *http.Request) operatorPromptIdentityInfo {
525		if user := r.Header.Get("X-Tailscale-User"); user != "" {
526			return operatorPromptIdentityInfo{kind: "tsnet", actor: user}
527		}
528		if r.RemoteAddr != "" {
529			return operatorPromptIdentityInfo{kind: "localhost", actor: "localhost:" + r.RemoteAddr}
530		}
531		return operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
532	}
533	
534	// validateSameOrigin enforces strict Origin/Host equality on prompt-driven
535	// mutations. When the request carries an Origin header (every browser POST
536	// does), the host portion must match the request Host — this rejects
537	// browser cross-origin POSTs even from a trusted-loopback peer (defense in
538	// depth alongside the per-session CSRF token). Non-browser clients (curl,
539	// the SvelteKit fetch wrapper running same-origin) either omit Origin or
540	// emit an Origin matching Host, so they pass through unchanged.
541	func validateSameOrigin(r *http.Request) error {
542		origin := r.Header.Get("Origin")
543		if origin == "" {
544			// No Origin -> not a browser cross-origin POST. CSRF token is the
545			// remaining gate.
546			return nil
547		}
548		parsed, err := url.Parse(origin)
549		if err != nil || parsed.Host == "" {
550			return errCrossOrigin
551		}
552		if !sameHost(parsed.Host, r.Host) {
553			return errCrossOrigin
554		}
555		return nil
556	}
557	
558	// sameHost compares two host[:port] strings tolerating an absent port (a
559	// browser may omit :443 from Origin while the request Host carries it, or
560	// vice versa). The comparison is case-insensitive on the host component.
561	func sameHost(a, b string) bool {
562		ah, _ := splitHostPort(a)
563		bh, _ := splitHostPort(b)
564		if !strings.EqualFold(ah, bh) {
565			return false
566		}
567		// Reject when both sides carry a port and they disagree; tolerate the
568		// "one side omits the port" case (default-port elision by the browser).
569		_, ap := splitHostPort(a)
570		_, bp := splitHostPort(b)
571		if ap != "" && bp != "" && ap != bp {
572			return false
573		}
574		return true
575	}
576	
577	func splitHostPort(hp string) (string, string) {
578		if i := strings.LastIndex(hp, ":"); i > 0 && !strings.Contains(hp[i:], "]") {
